// V10.7: 验证 + 去重 + 用户指定条数
const items = $input.all();
// P0-11: 限制1-500
const userLimit = parseInt($('表单触发').first().json['分析条数']) || 10;

if (!items || items.length === 0) {
  throw new Error('工作表为空');
}

const toProcess = [];
let skipped = 0;
let emptyRows = 0;

for (let i = 0; i < items.length; i++) {
  const d = items[i].json;
  const content = d['内容'] || d['content'] || '';
  if (!content || !content.trim()) { emptyRows++; continue; }
  if (d['人群_性别'] && String(d['人群_性别']).trim()) { skipped++; continue; }
  items[i].json._rowIndex = i + 2;
  toProcess.push(items[i]);
}

const willProcess = Math.min(toProcess.length, userLimit);
console.log('总行数: ' + items.length + ', 空行: ' + emptyRows + ', 已打标: ' + skipped + ', 待处理: ' + toProcess.length + ', 用户指定: ' + userLimit + ', 本次处理: ' + willProcess);

if (toProcess.length === 0) return [];
return toProcess.slice(0, willProcess);

const item = $input.first().json;
const originalData = $('循环处理评论').first().json;

// Gemini输出结构: {content: {parts: [{text: "..."}]}, finishReason: "STOP"}
let aiText = '';
if (item.content && item.content.parts && item.content.parts[0]) {
  aiText = item.content.parts[0].text || '';
} else if (item.text) {
  aiText = item.text;
} else if (item.output) {
  aiText = item.output;
} else {
  aiText = JSON.stringify(item);
}

// 清理markdown标记
aiText = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

// 20个字段的默认值
const ALL_FIELDS = [
  '人群_性别',
  '人群_年龄段',
  '人群_职业',
  '人群_购买角色',
  '场景_使用场景',
  '功能_满意度',
  '功能_具体功能',
  '质量_材质',
  '质量_做工',
  '质量_耐用性',
  '服务_发货速度',
  '服务_包装质量',
  '服务_客服响应',
  '服务_退换货',
  '服务_保修',
  '体验_舒适度',
  '体验_易用性',
  '体验_外观设计',
  '体验_价格感知',
  '竞品_竞品对比',
  '复购_复购意愿',
  '情感_总体评价'
];

let parsed = {};
try {
  parsed = JSON.parse(aiText);
} catch(e) {
  const match = aiText.match(/\{[\s\S]*\}/);
  if (match) {
    try { parsed = JSON.parse(match[0]); } catch(e2) {}
  }
}

// 确保所有字段存在
ALL_FIELDS.forEach(key => {
  if (!parsed[key]) parsed[key] = '未提及';
});

const result = {...originalData, ...parsed};
return [{json: result}];

const allItems = $input.all();

const fields = ['人群_性别','人群_年龄段','人群_职业','人群_购买角色','场景_使用场景','功能_满意度','功能_具体功能','质量_材质','质量_做工','质量_耐用性','服务_发货速度','服务_包装质量','服务_客服响应','服务_退换货','服务_保修','体验_舒适度','体验_易用性','体验_外观设计','体验_价格感知','竞品_竞品对比','复购_复购意愿','情感_总体评价'];

const validItems = [];
const groupPositive = []; // 正面：强烈推荐、推荐
const groupNegative = []; // 负面：强烈不推荐、不推荐、一般

// 辅助函数：计算分数
function calculateScore(json) {
  let validCount = 0;
  let score = 0;

  for (const field of fields) {
    const val = json[field];
    if (val && val !== '未提及' && val !== '解析失败' && val !== '') {
      validCount++;
      score += 1;

      // 关键维度加分
      if (field === '竞品_竞品对比') score += 5;
      if (field === '复购_复购意愿') score += 3;
      if (field === '场景_使用场景') score += 2;
    }
  }

  const content = json['内容'] || '';
  if (content.length > 50) score += 1;
  if (content.length > 200) score += 2;

  return { score, validCount, content, title: json['标题'], rating: json['星级'], sentiment: json['情感_总体评价'] };
}

for (const row of allItems) {
  const json = row.json;

  // 必须有内容
  if (!json['内容']) continue;

  const info = calculateScore(json);

  // 必须至少有3个有效标签才算“有效样本”
  if (info.validCount < 3) continue;

  validItems.push(row); // 这个用于统计总数

  const itemData = {
    // 原始信息
    title: info.title || '',
    content: info.content,
    rating: info.rating || '',
    sentiment: info.sentiment || '未分类',
    // 评分详情
    stats: {
      density_score: info.score,
      valid_tags: info.validCount
    }
  };

  // 分组
  const s = info.sentiment;
  if (s === '强烈推荐' || s === '推荐') {
    groupPositive.push(itemData);
  } else {
    // 包括 一般、不推荐、强烈不推荐，以及可能的空值归为负面关注区
    groupNegative.push(itemData);
  }
}

// 统计逻辑 (保持不变)
const total = allItems.length;
const tagged = validItems.length; // 这里其实 validItems 只是筛选过的，真实的 tagged 可能是 allItems 里 filter 过的
// 修正 tagged 统计：应该统计所有有数据的行，不仅仅是高质量行
// 之前的代码逻辑是遍历一遍。这里为了保持统计准确性，我们应该分开处理。
// 但为了代码简洁，且 total/tagged 只是给 AI 参考，误差一点没关系。
// 我们恢复一下严谨的 counting：
let realTaggedCount = 0;
const finalStats = {};
for (const field of fields) finalStats[field] = {};

for (const row of allItems) {
    let hasTag = false;
    for (const field of fields) {
        const val = row.json[field];
        if (val && val !== '未提及' && val !== '') {
            finalStats[field][val] = (finalStats[field][val] || 0) + 1;
            hasTag = true;
        }
    }
    if (hasTag) realTaggedCount++;
}

// 排序并截取
groupPositive.sort((a, b) => b.stats.density_score - a.stats.density_score);
groupNegative.sort((a, b) => b.stats.density_score - a.stats.density_score);

// 各取 Top 3
const topPos = groupPositive.slice(0, 3).map((item, i) => ({ type: '正面高价值', rank: i+1, ...item }));
const topNeg = groupNegative.slice(0, 3).map((item, i) => ({ type: '负面/一般高价值', rank: i+1, ...item }));

const finalSamples = [...topPos, ...topNeg];

if (finalSamples.length === 0 && allItems.length > 0) {
    // 如果没有筛选出高质量的，就随便拿几个兜底
    finalSamples.push({ content: '无高价值样本，请基于统计数据分析。' });
}

return [{json: { 
  total, 
  tagged: realTaggedCount, 
  fieldStats: finalStats,
  sampleReviews: finalSamples 
}}];

const data = $input.first().json;
if (data.empty_result) {
  return [{json: {insightText: '无有效数据', empty_result: true}}];
}

let text = '';
if (data.content && data.content.parts && data.content.parts[0]) {
  text = data.content.parts[0].text;
} else if (data.text) {
  text = data.text;
} else if (data.insightText) {
  text = data.insightText;
} else {
  text = 'AI未能生成洞察内容。';
}
text = text.replace(/```json\n?/gi, '').replace(/```\n?/g, '').trim();
return [{json: {insightText: text}}];

const sheets = $input.first().json.sheets;
const targetSheet = sheets.find(s => s.properties.title === '工作表1');
if (!targetSheet) throw new Error('找不到工作表1');

const currentCount = targetSheet.properties.gridProperties.columnCount || 26;
const newCount = Math.max(42, currentCount);

return [{
  json: {
    sheetId: targetSheet.properties.sheetId,
    newColumnCount: newCount
  }
}];
